A basic calculation function test suite block:

```cpp
#include <cassert>

float CalculateXPToNextLevel(int Level) {
    return Level * 100.0f;
}

void TestXPFormula() {
    // Assertions check assumptions at runtime or compile-time
    assert(CalculateXPToNextLevel(1) == 100.0f);
    assert(CalculateXPToNextLevel(2) == 200.0f);
    assert(CalculateXPToNextLevel(5) == 500.0f);
}
```
